const shift=28800;
const stations={A:{cycle:38,uptime:0.94},B:{cycle:51,uptime:0.88},C:{cycle:44,uptime:0.91}};
for(const [k,v] of Object.entries(stations)){
  const cap=shift/v.cycle*v.uptime;
  console.log(k, cap.toFixed(12));
}
const caps=Object.fromEntries(Object.entries(stations).map(([k,v])=>[k,shift/v.cycle*v.uptime]));
console.log('demand',620);
console.log('order',Object.entries(caps).sort((a,b)=>a[1]-b[1]).map(([k,v])=>`${k}:${v}`));
console.log('A-B pct',(caps.A-caps.B)/caps.B*100);
console.log('B-C pct',(caps.B-caps.C)/caps.C*100);
console.log('A-C pct',(caps.A-caps.C)/caps.C*100);
